Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // test itself fails if it exceeds 5s
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("fast response", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass TestContext.CancellationToken for cooperative timeout
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    // Reusable fake handler — avoids mocking frameworks entirely
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + `_testContext.CancellationToken` — MSTest cancels the token when time expires |
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| **No mocking framework needed** | A simple `FakeHttpMessageHandler` gives full control over responses and delays |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` — lets you inspect the exception |
| **Sealed class + constructor injection** | `TestContext` injected via constructor, class is `sealed` for performance |

The critical detail: always flow `TestContext.CancellationToken` into your async calls when using `[Timeout]`. Without it, the timeout kills the test thread but the underlying HTTP call keeps running.
